SELECT i.id, i.start_at AS startAt, i.end_at AS endAt, i.type AS interviewType, et.name AS interviewTypeName, i.evaluator_no AS evaluatorNo, e.name AS evaluatorName, i.evaluatee_no AS evaluateeNo, u.name AS evaluateeName, i.place, c.name AS statusName FROM interview_52 i LEFT JOIN eval_type_52 et ON i.type = et.id LEFT JOIN employee_52 e ON i.evaluator_no = e.emp_no LEFT JOIN employee_52 u ON i.evaluatee_no = u.emp_no LEFT JOIN code_common_52 c ON c.code = CAST(i.status AS varchar) AND c.group_id = 4 WHERE (i.evaluator_no = #{empNo} OR i.evaluatee_no = #{empNo})
AND CAST(i.start_at AS DATE) = #{startDay}
AND (i.evaluator_no = #{employee} OR i.evaluatee_no = #{employee})
AND i.type = #{type}
AND i.status = #{status}
ORDER BY i.start_at DESC
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT COUNT(*) FROM interview_52 i LEFT JOIN eval_type_52 et ON i.type = et.id LEFT JOIN employee_52 e ON i.evaluator_no = e.emp_no LEFT JOIN employee_52 u ON i.evaluatee_no = u.emp_no LEFT JOIN code_common_52 c ON c.code = CAST(i.status AS varchar) AND c.group_id = 4 WHERE (i.evaluator_no = #{empNo} OR i.evaluatee_no = #{empNo})
AND CAST(i.start_at AS DATE) = #{startDay}
AND (i.evaluator_no = #{employee} OR i.evaluatee_no = #{employee})
AND i.type = #{type}
AND i.status = #{status}
